VALUES
  ('optometrist-moex-01854', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '若在頂點距離為12.0mm處，以 -9.50D的透鏡矯正簡化眼，假設此簡化眼的屈光力為 +60.00D，平均折 射率n=1.333，試求眼軸長度為何？', '["25.15mm", "25.90mm", "26.66mm", "27.20mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01855', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '簡易模型眼，正視眼相關參數下列何者錯誤？', '["簡易模型眼的假設之一是看遠方物件時是沒有進行調節的狀態", "折射率為n=1.333", "眼軸長為22.22mm", "全眼等效屈光力為 +58D"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01856', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '關於看手機時所需的調節力（accommodation）敘述，下列何者正確？①近視眼戴隱形眼鏡，比戴一般眼鏡', '["遠視眼戴隱形眼鏡，比戴一般眼鏡時需更多的調焦", "戴隱形眼鏡時，遠視眼比相同 度數的近視眼需更多的調焦", "戴一般眼鏡時，近視眼比相同度數的遠視眼需更少的調焦", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01857', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '遠視 +1.00DS顧客擁有以下四副眼鏡，其調節力為4.0D，若想保留其一半調節力，且看清楚眼前80公 分至35公分範圍，下列那副眼鏡較合適？', '["+1.00DS", "+1.50DS", "+2.00DS", "+2.50DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01858', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '有一無水晶體顧客，可用 +13.00DS眼鏡（VD=15mm）矯正看遠清楚，但是看近時須將眼鏡向前推到 眼前2.3公分處才能看清近物，因為他缺乏多少眼球調節力？', '["2.0D", "2.4D", "2.8D", "3.0D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01859', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '一位病患經過視網膜檢影鏡檢查及驗光結果顯示雙眼 +4.00DS。若此病患配戴 +3.50DS眼鏡，在調節幅 度為5.5D的狀況下，病患的調節最近點會在下列何處？', '["12.5cm", "15cm", "17.5cm", "20cm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01860', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '有關稜鏡之特性，下列敘述何者正確？', '["稜鏡本身無聚散度（vergence）之效果", "稜鏡會將光束往鏡尖（apex）方向折射", "稜鏡會將物體的影像位置往基底（base）方向偏移", "稜鏡因不同的擺放的方式造成光束入射角的改變，並不會改變其稜鏡效應（prismaticeffect）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01861', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '一名正視眼的病人，有 100 公分的超焦距離（hyperfocal distance），真正調節幅度（true amplitude of accommodation）為4.0D。所以這位病人能看清楚的最近距離為多少？', '["20公分", "25公分", "50公分", "100公分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01862', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '在25cm處閱讀時，下列何者錯誤？', '["正視眼者需約4.00D的調節力", "配戴隱形眼鏡者亦需約4.00D的調節力", "在配戴一般眼鏡下，遠視患者需要較高的調節力", "在配戴一般眼鏡下，遠視患者需要較少的內聚力（convergence）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01863', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '一個遠視 +2.00D的人，在頂點距離12mm處配戴一個 +1.95D度數之眼鏡，當此人要看清楚眼前20公分 處的東西，需要使用多少的調節力？', '["4.7D", "5.0D", "5.2D", "5.8D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "ddd70016c098", "answer_pdf_sha1": "e59ae4ae3197", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
